sys_script_include.script:
var GetWorkspaceLocation = Class.create();
GetWorkspaceLocation.prototype = Object.extendsObject(global.AbstractAjaxProcessor, {
	getWorkspaceLocation: function (){
		// Get the sys ID of the location 
		var workspaceId = this.getParameter("sysparm_workspace_id");

		var workspaceGr = new GlideRecord("x_1759267_wrm_workspace_options");

        if (workspaceGr.get("sys_id", workspaceId)) {
            var location = workspaceGr.getValue("location");
            var image = workspaceGr.getValue("image");
            return JSON.stringify({ location, image }); // return the source field value
        }
        return '';
	},
    type: 'GetWorkspaceLocation'
});
